// Generator for Tests 3 and 4
// Run: node gen-tests34.js
const fs = require('fs');

function q(id,mod,num,type,skill,passage,stem,choices,answer,explanation,difficulty){
  return {id,module:mod,questionNumber:num,type,skill,passage:passage||'',stem,choices,answer,explanation,difficulty};
}
function gq(id,mod,num,skill,stem,answer,explanation,difficulty){
  return q(id,mod,num,'gridin',skill,'',stem,null,answer,explanation,difficulty);
}

// Shuffle MC answers to hit target distribution
function shuffleToTarget(questions, targets) {
  const mc = questions.filter(q => q.choices);
  mc.forEach((q, i) => {
    if (i >= targets.length) return;
    const target = targets[i];
    const curIdx = q.choices.findIndex(c => c[0] === q.answer);
    const correctText = q.choices[curIdx].slice(3);
    const others = q.choices.filter((_,j) => j !== curIdx).map(c => c.slice(3));
    const tIdx = target.charCodeAt(0) - 65;
    const newChoices = [...others];
    newChoices.splice(tIdx, 0, correctText);
    q.choices = newChoices.map((t, i) => String.fromCharCode(65+i) + ') ' + t);
    q.answer = target;
  });
  return questions;
}

