// Shuffle MC answer distributions for balanced distribution
const t5656 = 'ABCDA BCDA BCDA BCDA BCDA B'.split(' ').join('').split('');
const t6556 = 'BCDAB CDAB CDAB CDAB CDAB CD'.split(' ').join('').split('');

function shuffleTo(questions, targets) {
  const mc = questions.filter(q => q.choices);
  mc.forEach((q, i) => {
    if (i >= targets.length) return;
    const target = targets[i];
    const curIdx = q.choices.findIndex(c => c[0] === q.answer);
    if (curIdx < 0) return;
    const correctText = q.choices[curIdx].slice(3);
    const others = q.choices.filter((_,j) => j !== curIdx).map(c => c.slice(3));
    const tIdx = target.charCodeAt(0) - 65;
    const newChoices = [...others];
    newChoices.splice(tIdx, 0, correctText);
    q.choices = newChoices.map((t, i) => String.fromCharCode(65+i) + ') ' + t);
    q.answer = target;
  });
}

shuffleTo(t3rw1, t5656);
shuffleTo(t3rw2, t6556);
shuffleTo(t3m1, t5656);
shuffleTo(t3m2, t6556);
